import React, { useContext } from 'react';
import PlanetsContext from '../contexts/PlanetsContext';

function SearchFilter() {
  const { planets, setPlanets, filter, setFilter } = useContext(PlanetsContext);

  const filterPlanets = (value) => {
    setFilter(value);

    // const filteredPlanets = planets.filter((planet) => planet.name.includes(filter));
    // setPlanets(filteredPlanets);
  };

  return (
    <label htmlFor="search-filter">
      Filtro
      <input
        type="text"
        data-testid="name-filter"
        id="search-filter"
        value={ filter }
        onChange={ (e) => filterPlanets(e.target.value) }
      />
    </label>
  );
}

export default SearchFilter;
